mapper.delete:
delete
from cf_srm_eaf_rec
where sys_no=#{sysNo} and check_rec_id=#{recId};

mapper.select:
select id,eaf_detail_id  as eafDetailId,sys_no as sysNo,check_rec_id as checkRecId
     ,step_no as stepNo,check_proc_desc as checkProcDesc
,checker as checker,dept as dept,check_datetime as checkDatetime,check_result as checkResult
     ,check_desc as checkDesc,is_current_step as isCurrentStep,
check_user as checkUser,checker_string as checkerString
from cf_srm_eaf_rec
where 1=1

    and id=#{eafRecDto.id}


    and sys_no=#{eafRecDto.sysNo}


    and check_rec_id=#{eafRecDto.checkRecId}


    and step_no=#{eafRecDto.stepNo}


    and is_current_step=#{eafRecDto.isCurrentStep}


    and check_result=#{eafRecDto.checkResult}

LIMIT 1
